    "And the sons of <span class=\"person\">Eliphaz</span> were <span class=\"person\">Teman</span>, <span class=\"person\">Omar</span>, <span class=\"person\">Zepho</span>, and <span class=\"person\">Gatam</span>, and <span class=\"person\">Kenaz</span>.",
